#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""Tune lock_timeout 3s -> 15s (exit-0-safe): still kills the 300-800s gridlocks but lets
normal worker writes through (3s was cancelling legit writes -> worker crashes). Restart QA,
verify, capture fresh error if any still fail."""
import os,sys,json,time,subprocess
def sh(c,t=45):
    try:
        r=subprocess.run(["bash","-lc",c],capture_output=True,text=True,timeout=t);return (r.stdout+r.stderr).strip()
    except Exception: return "ERR"
def psql(q,t=15):
    r=subprocess.run(["sudo","-u","postgres","psql","tuanichat_atlas","-tAc",q],capture_output=True,text=True,timeout=t)
    return (r.stdout.strip().split('\n')[-1] if r.returncode==0 and r.stdout.strip() else "ERR")
out={"kind":"locktune","ts":int(time.time())}
try:
    out["set"]=psql("ALTER DATABASE tuanichat_atlas SET lock_timeout='15s'"); psql("SELECT pg_reload_conf()")
    out["cur"]=psql("SELECT 'lock='||current_setting('lock_timeout')||' idle='||current_setting('idle_in_transaction_session_timeout')")
    sh("systemctl reset-failed 'atlas-qa-auditor@*' 2>/dev/null")
    out["restart"]=sh("systemctl restart $(for i in $(seq 1 10); do echo atlas-qa-auditor@$i.service; done) 2>&1 | tail -1; echo done")
    time.sleep(35)  # let them run past the startup + a few work cycles
    out["qa_active"]=sh("systemctl list-units 'atlas-qa-auditor@*.service' --state=active --no-legend --plain 2>/dev/null|wc -l")
    out["qa_failed"]=sh("systemctl list-units 'atlas-qa-auditor@*.service' --no-legend --plain 2>/dev/null | awk '$4==\"auto-restart\"||$3==\"failed\"{c++}END{print c+0}'")
    out["qa2_fresh"]=sh("journalctl -u atlas-qa-auditor@2.service --since '40 sec ago' --no-pager 2>&1 | grep -iE 'Error|Exception|Traceback|Lock|lock' | tail -5")
    out["qa2_report"]=sh("journalctl -u atlas-qa-auditor@2.service --since '40 sec ago' --no-pager 2>&1 | grep -iE 'REPORT|audited' | tail -2")
except Exception as e: out["error"]=str(e)
def envf(p):
    d={}
    try:
        for ln in open(p):
            ln=ln.strip()
            if ln.startswith('export '): ln=ln[7:]
            if '=' in ln and not ln.startswith('#'):
                k,v=ln.split('=',1); d[k.strip()]=v.strip().strip('"').strip("'")
    except Exception: pass
    return d
try:
    import base64,urllib.request,urllib.error
    env=envf("/etc/atlas/autopull.env"); tok=env.get("STATUS_TOKEN") or os.environ.get("STATUS_TOKEN"); repo=env.get("STATUS_REPO") or "cloudwalker171/atlas-manifests"
    url="https://api.github.com/repos/%s/contents/status/hetzner/locktune.json"%repo; sha=None
    if tok:
        try:
            r=urllib.request.Request(url+"?ref=main",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); sha=json.load(urllib.request.urlopen(r,timeout=20)).get("sha")
        except Exception: sha=None
        body={"message":"locktune","content":base64.b64encode(json.dumps(out,indent=2,default=str).encode()).decode(),"branch":"main"}
        if sha: body["sha"]=sha
        for _ in range(6):
            try:
                rq=urllib.request.Request(url,data=json.dumps(body).encode(),method="PUT",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas","Content-Type":"application/json"}); urllib.request.urlopen(rq,timeout=25); break
            except urllib.error.HTTPError as e:
                if e.code==409:
                    try:
                        rq2=urllib.request.Request(url+"?ref=main",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); body["sha"]=json.load(urllib.request.urlopen(rq2,timeout=20)).get("sha")
                    except Exception: pass
                else: break
            except Exception: time.sleep(2)
except Exception: pass
sys.exit(0)
